function parseFlags(flagArgs) {
  const out = {
    ci: false,
    force: false,
    pruneNodeModules: false,
    install: false,
    target: null,
    noSave: false,
    checkCleanGit: false,
    pruneCache: false
  };

  for (const a of flagArgs) {
    if (a === '--ci') out.ci = true;
    else if (a === '--force') out.force = true;
    else if (a === '--pruneNodeModules') out.pruneNodeModules = true;
    else if (a === '--install') out.install = true;
    else if (a === '--noSave') out.noSave = true;
    else if (a === '--checkCleanGit') out.checkCleanGit = true;
    else if (a === '--pruneCache') out.pruneCache = true;
    else if (a.startsWith('--target=')) out.target = a.slice('--target='.length).trim();
    else fail(`Unknown option: ${a}`);
  }
  return out;
}

function ensureNodeProject() {
  if (!fs.existsSync(PKG_JSON)) fail('package.json not found at project root.');
}

function ensureNpmConfig() {
  // Encourage deterministic behavior without modifying repo unless requested externally.
  // We only warn if npmrc missing; no auto-write by default.
  if (!fs.existsSync(NPMRC)) {
    // Not failing; informational.
    log('INFO: .npmrc not found. Consider adding one for consistent installs (e.g., "fund=false", "audit=false").');
  }
}

function resolveNpm() {
  const npmCmd = process.platform === 'win32' ? 'npm.cmd' : 'npm';
  const r = spawnSync(npmCmd, ['--version'], { cwd: ROOT, stdio: 'pipe' });
  if (r.error) fail(`npm not found in PATH: ${r.error.message}`);
  if (r.status !== 0) fail(`npm --version failed: ${String(r.stderr || '')}`);
  return npmCmd;
}

function run(bin, binArgs, opts) {
  const res = spawnSync(bin, binArgs, { ...opts, stdio: 'inherit' });
  if (res.error) fail(res.error.message);
  if (res.status !== 0) fail(`${bin} ${binArgs.join(' ')} exited with code ${res.status}`);
}

function readJson(p) {
  try {
    return JSON.parse(fs.readFileSync(p, 'utf8'));
  } catch (e) {
    fail(`Failed to read JSON at ${p}: ${e.message}`);
  }
}

function findProjectRoot(start) {
  let dir = path.resolve(start);
  while (true) {
    if (fs.existsSync(path.join(dir, 'package.json'))) return dir;
    const parent = path.dirname(dir);
    if (parent === dir) return null;
    dir = parent;
  }
}

function fail(msg) {
  process.stderr.write(String(msg).trimEnd() + '\n');
  process.exit(1);
}

function log(msg) {
  process.stdout.write(String(msg).trimEnd() + '\n');
}

function isGitRepo(dir) {
  return fs.existsSync(path.join(dir, '.git'));
}

function gitStatusPorcelain(dir) {
  const gitCmd = process.platform === 'win32' ? 'git.exe' : 'git';
  const res = spawnSync(gitCmd, ['status', '--porcelain'], { cwd: dir, stdio: 'pipe' });
  if (res.error) return '';
  if (res.status !== 0) return '';
  return String(res.stdout || '');
}

function guessScriptPath() {
  const candidates = [
    path.join('scripts', 'lockfile.js'),
    path.join('tools', 'lockfile.js'),
    'lockfile.js'
  ];
  for (const c of candidates) {
    if (fs.existsSync(path.join(process.cwd(), c))) return c.replace(/\\/g, '/');
    if (fs.existsSync(path.join(ROOT, c))) return c.replace(/\\/g, '/');
  }
  return path.relative(process.cwd(), __filename).replace(/\\/g, '/');
}